// === CONFIG ===
// Set these in n8n → Settings → Environment Variables
// AMPLITUDE_API_KEY  and  AMPLITUDE_SECRET_KEY
// OR replace the fallback strings below with your actual keys.
const API_KEY = $env.AMPLITUDE_API_KEY  || '6d32ffa2d1954f01a262fcdbb0a3e7b1';
const SECRET  = $env.AMPLITUDE_SECRET_KEY || '716dfa8ea6e2aa4a4e8cef3cdf3b6fb3';

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const pad = n => String(n).padStart(2, '0');
const dateStr = `${yesterday.getFullYear()}${pad(yesterday.getMonth()+1)}${pad(yesterday.getDate())}`;

const auth    = 'Basic ' + Buffer.from(`${API_KEY}:${SECRET}`).toString('base64');
const FILTERS = JSON.stringify([
  {prop: 'gp:utm_medium',  op: 'is',     values: ['Influencers']},
  {prop: 'gp:utm_content', op: 'is not', values: ['adaff']}
]);
const GROUP = 'gp:utm_campaign';

const EVENTS = [
  'Viewed Marketing Site Landing Page',
  'G_account_created',
  'G_delegation_enabled'
];

async function fetchEvent(eventName) {
  const params = new URLSearchParams({
    e:     JSON.stringify({event_type: eventName}),
    s:     FILTERS,
    g:     GROUP,
    start: dateStr,
    end:   dateStr,
    m:     'totals',
    i:     '1'
  });
  const res = await fetch(
    `https://amplitude.com/api/2/events/segmentation?${params}`,
    { headers: { Authorization: auth } }
  );
  if (!res.ok) throw new Error(`Amplitude ${res.status} for "${eventName}": ${await res.text()}`);
  return (await res.json()).data;
}

const [d0, d1, d2] = await Promise.all(EVENTS.map(fetchEvent));
const allData = { [EVENTS[0]]: d0, [EVENTS[1]]: d1, [EVENTS[2]]: d2 };

const combined = {};
for (const [eventName, data] of Object.entries(allData)) {
  const labels  = data.seriesLabels || [];
  const series  = data.series       || [];
  const xValues = data.xValues      || [];
  for (let i = 0; i < labels.length; i++) {
    const campaign = Array.isArray(labels[i]) ? labels[i][0] : labels[i];
    const counts   = series[i] || [];
    for (let j = 0; j < xValues.length; j++) {
      const key = `${campaign}||${xValues[j]}`;
      if (!combined[key]) {
        combined[key] = {
          utm_Campaign: campaign,
          date: xValues[j],
          'Viewed Marketing Site Landing Page': 0,
          G_account_created:   0,
          G_delegation_enabled: 0
        };
      }
      combined[key][eventName] = counts[j] || 0;
    }
  }
}

return Object.values(combined).map(row => ({ json: row }));
